uestedWindowEndAt" TIMESTAMP(3) NOT NULL,     "voucherCode" TEXT,     "breakdownJson" JSONB NOT NULL,     "currency" TEXT NOT NULL,     "estimatedFirstPlayAt" TIMESTAMP(3),     "expiresAt" TIMESTAMP(3) NOT NULL,     "createdAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "Quote_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "Order" (     "id" TEXT NOT NULL,     "publicToken" TEXT NOT NULL,     "locale" TEXT NOT NULL,     "customerName" TEXT NOT NULL,     "customerEmail" TEXT NOT NULL,     "customerPhone" TEXT NOT NULL,     "status" "OrderStatus" NOT NULL,     "quoteId" TEXT NOT NULL,     "paymentMode" TEXT NOT NULL,     "paymentSessionId" TEXT,     "paymentReference" TEXT,     "stripeEventId" TEXT,     "appliedVoucherCode" TEXT,     "totalCents" INTEGER NOT NULL,     "currency" TEXT NOT NULL,     "requestedWindowStartAt" TIMESTAMP(3) NOT NULL,     "requestedWindowEndAt" TIMESTAMP(3) NOT NULL,     "estimatedFirstPlayAt" TIMESTAMP(3),     "actualFirstPlayAt" TIMESTAMP(3),     "paidAt" TIMESTAMP(3),     "approvedAt" TIMESTAMP(3),     "rejectedAt" TIMESTAMP(3),     "rightsAccepted" BOOLEAN NOT NULL,     "policyAccepted" BOOLEAN NOT NULL,     "createdAt" TIMESTAMP(3) NOT NULL,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "Order_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "OrderItem" (     "id" TEXT NOT NULL,     "orderId" TEXT NOT NULL,     "submissionId" TEXT NOT NULL,     "screenId" TEXT NOT NULL,     "mediaType" "MediaType" NOT NULL,     "renderDurationSeconds" INTEGER NOT NULL,     "repeatEveryMinutes" INTEGER,     "requestedWindowStartAt" TIMESTAMP(3) NOT NULL,     "requestedWindowEndAt" TIMESTAMP(3) NOT NULL,     "quoteBreakdownJson" JSONB NOT NULL,     "scheduledSlotIds" TEXT[],     "messageTemplate" TEXT NOT NULL,     "createdAt" TIMESTAMP(3) NOT NULL,     "updatedAt" TIMESTAMP(3) NOT NULL,      CONSTRAINT "OrderItem_pkey" PRIMARY KEY ("id") );  -- CreateTable CREATE TABLE "PlaySlot" (     "id" TEXT NOT NULL,     "screenId" TEXT NOT NU